SELECT id, username, email, password_hash, nickname, avatar_url, bio, status, created_at, updated_at
FROM `user`
WHERE id = #{id}

SELECT id, username, email, password_hash, nickname, avatar_url, bio, status, created_at, updated_at
FROM `user`
WHERE username = #{username}

SELECT id, username, email, password_hash, nickname, avatar_url, bio, status, created_at, updated_at
FROM `user`
WHERE email = #{email}
